# For loop to delete sensitive files (Landing):

for folder_name in folder_names:
    try:
        raw_output_path = f"abfss://{destination_container}@{destination_storage}.dfs.core.windows.net/{folder_name}"
        mssparkutils.fs.rm(raw_output_path,recurse=True)
        print(f"Folder {folder_name} deleted successfully.")

    except Exception as e:
            print(f"Folder {folder_name} does not exist.")

